#!/usr/bin/env node

const { Client } = require('pg');

const SCHEMA_SQL = [
  `
  CREATE TABLE IF NOT EXISTS sessions (
    sid TEXT PRIMARY KEY,
    sess JSONB NOT NULL,
    expire TIMESTAMP NOT NULL
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS participant (
    strava_athlete_id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    active BOOLEAN NOT NULL DEFAULT TRUE,
    is_admin BOOLEAN NOT NULL DEFAULT FALSE,
    weight DOUBLE PRECISION,
    weight_updated_at TIMESTAMPTZ
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS season (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    name TEXT NOT NULL,
    start_at BIGINT NOT NULL,
    end_at BIGINT NOT NULL,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS segment (
    strava_segment_id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    distance DOUBLE PRECISION,
    average_grade DOUBLE PRECISION,
    start_latitude DOUBLE PRECISION,
    start_longitude DOUBLE PRECISION,
    end_latitude DOUBLE PRECISION,
    end_longitude DOUBLE PRECISION,
    city TEXT,
    state TEXT,
    country TEXT,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    metadata_updated_at TIMESTAMPTZ,
    total_elevation_gain DOUBLE PRECISION,
    climb_category BIGINT
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS week (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    season_id BIGINT NOT NULL REFERENCES season(id),
    week_name TEXT NOT NULL,
    strava_segment_id TEXT NOT NULL REFERENCES segment(strava_segment_id),
    required_laps BIGINT NOT NULL DEFAULT 1,
    start_at BIGINT NOT NULL,
    end_at BIGINT NOT NULL,
    multiplier BIGINT NOT NULL DEFAULT 1,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    notes TEXT DEFAULT ''
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS activity (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    week_id BIGINT NOT NULL REFERENCES week(id),
    strava_athlete_id TEXT NOT NULL REFERENCES participant(strava_athlete_id),
    strava_activity_id TEXT NOT NULL,
    start_at BIGINT NOT NULL,
    device_name TEXT,
    validation_status TEXT DEFAULT 'valid',
    validation_message TEXT,
    validated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    athlete_weight DOUBLE PRECISION
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS segment_effort (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    activity_id BIGINT NOT NULL REFERENCES activity(id),
    strava_segment_id TEXT NOT NULL REFERENCES segment(strava_segment_id),
    strava_effort_id TEXT,
    effort_index BIGINT NOT NULL,
    elapsed_seconds BIGINT NOT NULL,
    start_at BIGINT NOT NULL,
    pr_achieved BIGINT,
    average_watts DOUBLE PRECISION,
    average_heartrate DOUBLE PRECISION,
    max_heartrate DOUBLE PRECISION,
    average_cadence DOUBLE PRECISION,
    device_watts BOOLEAN
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS result (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    week_id BIGINT NOT NULL REFERENCES week(id),
    strava_athlete_id TEXT NOT NULL REFERENCES participant(strava_athlete_id),
    activity_id BIGINT REFERENCES activity(id),
    total_time_seconds BIGINT NOT NULL,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS participant_token (
    strava_athlete_id TEXT PRIMARY KEY REFERENCES participant(strava_athlete_id) ON DELETE CASCADE,
    access_token TEXT NOT NULL,
    refresh_token TEXT NOT NULL,
    expires_at BIGINT NOT NULL,
    scope TEXT,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS deletion_request (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    strava_athlete_id TEXT NOT NULL,
    requested_at TIMESTAMPTZ NOT NULL,
    status TEXT DEFAULT 'pending',
    completed_at TIMESTAMPTZ
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS schema_migrations (
    version TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    executed_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS webhook_event (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    payload TEXT NOT NULL,
    processed BIGINT,
    error_message TEXT,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS webhook_subscription (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    verify_token TEXT NOT NULL,
    subscription_payload TEXT,
    subscription_id BIGINT,
    last_refreshed_at TIMESTAMPTZ
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS explorer_campaign (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    start_at BIGINT NOT NULL,
    end_at BIGINT NOT NULL,
    display_name TEXT,
    rules_blurb TEXT,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS explorer_destination (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    explorer_campaign_id BIGINT NOT NULL REFERENCES explorer_campaign(id) ON DELETE CASCADE,
    strava_segment_id TEXT NOT NULL,
    source_url TEXT,
    cached_name TEXT,
    display_label TEXT,
    display_order BIGINT NOT NULL DEFAULT 0,
    surface_type TEXT,
    category TEXT,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS explorer_destination_match (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    explorer_campaign_id BIGINT NOT NULL REFERENCES explorer_campaign(id) ON DELETE CASCADE,
    explorer_destination_id BIGINT NOT NULL REFERENCES explorer_destination(id) ON DELETE CASCADE,
    strava_athlete_id TEXT NOT NULL REFERENCES participant(strava_athlete_id) ON DELETE CASCADE,
    strava_activity_id TEXT NOT NULL,
    matched_at BIGINT NOT NULL,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS explorer_destination_pin (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    explorer_campaign_id BIGINT NOT NULL REFERENCES explorer_campaign(id) ON DELETE CASCADE,
    explorer_destination_id BIGINT NOT NULL REFERENCES explorer_destination(id) ON DELETE CASCADE,
    strava_athlete_id TEXT NOT NULL REFERENCES participant(strava_athlete_id) ON DELETE CASCADE,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS chain_wax_period (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    started_at BIGINT NOT NULL,
    ended_at BIGINT,
    total_distance_meters DOUBLE PRECISION NOT NULL DEFAULT 0,
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS chain_wax_activity (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    period_id BIGINT NOT NULL REFERENCES chain_wax_period(id),
    strava_activity_id TEXT NOT NULL UNIQUE,
    strava_athlete_id TEXT NOT NULL,
    distance_meters DOUBLE PRECISION NOT NULL,
    activity_start_at BIGINT NOT NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP
  )
  `,
  `
  CREATE TABLE IF NOT EXISTS chain_wax_puck (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    started_at BIGINT NOT NULL,
    wax_count BIGINT NOT NULL DEFAULT 0,
    is_current BOOLEAN NOT NULL DEFAULT TRUE,
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP
  )
  `,
  `CREATE INDEX IF NOT EXISTS idx_week_season ON week (season_id)`,
  `CREATE INDEX IF NOT EXISTS idx_sessions_expire ON sessions (expire)`,
  `CREATE INDEX IF NOT EXISTS idx_activity_status ON activity (validation_status)`,
  `CREATE INDEX IF NOT EXISTS idx_activity_week_participant ON activity (week_id, strava_athlete_id)`,
  `CREATE INDEX IF NOT EXISTS idx_segment_effort_activity ON segment_effort (activity_id)`,
  `CREATE INDEX IF NOT EXISTS idx_result_participant ON result (strava_athlete_id)`,
  `CREATE INDEX IF NOT EXISTS idx_result_week ON result (week_id)`,
  `CREATE INDEX IF NOT EXISTS idx_result_week_athlete ON result (week_id, strava_athlete_id)`,
  `CREATE INDEX IF NOT EXISTS idx_participant_token_participant ON participant_token (strava_athlete_id)`,
  `CREATE INDEX IF NOT EXISTS idx_webhook_event_created ON webhook_event (created_at)`,
  `CREATE INDEX IF NOT EXISTS idx_explorer_campaign_window ON explorer_campaign (start_at, end_at)`,
  `CREATE INDEX IF NOT EXISTS idx_explorer_destination_campaign ON explorer_destination (explorer_campaign_id)`,
  `CREATE INDEX IF NOT EXISTS idx_explorer_destination_segment ON explorer_destination (strava_segment_id)`,
  `CREATE UNIQUE INDEX IF NOT EXISTS idx_explorer_destination_campaign_segment ON explorer_destination (explorer_campaign_id, strava_segment_id)`,
  `CREATE INDEX IF NOT EXISTS idx_explorer_match_campaign_athlete ON explorer_destination_match (explorer_campaign_id, strava_athlete_id)`,
  `CREATE INDEX IF NOT EXISTS idx_explorer_match_activity ON explorer_destination_match (strava_activity_id)`,
  `CREATE UNIQUE INDEX IF NOT EXISTS idx_explorer_match_unique ON explorer_destination_match (explorer_campaign_id, explorer_destination_id, strava_athlete_id)`,
  `CREATE INDEX IF NOT EXISTS idx_explorer_pin_campaign_athlete ON explorer_destination_pin (explorer_campaign_id, strava_athlete_id)`,
  `CREATE UNIQUE INDEX IF NOT EXISTS idx_explorer_pin_unique ON explorer_destination_pin (explorer_campaign_id, explorer_destination_id, strava_athlete_id)`,
  `CREATE INDEX IF NOT EXISTS idx_chain_wax_activity_period ON chain_wax_activity (period_id)`,
  `CREATE INDEX IF NOT EXISTS idx_chain_wax_activity_strava_id ON chain_wax_activity (strava_activity_id)`
];

async function run() {
  const databaseUrl = process.env.DATABASE_URL;

  if (!databaseUrl) {
    throw new Error('DATABASE_URL is required');
  }

  const client = new Client({ connectionString: databaseUrl });

  try {
    await client.connect();

    for (const statement of SCHEMA_SQL) {
      await client.query(statement);
    }

    console.log('[BOOTSTRAP] Postgres schema bootstrap completed successfully');
  } finally {
    await client.end();
  }
}

run().catch((error) => {
  console.error(`[BOOTSTRAP] Failed: ${error instanceof Error ? error.message : String(error)}`);
  process.exit(1);
});
